/* ===== POOL DE QUESTIONS ANNALES — PASS/LAS ===== */
export const ANNALES_POOL = [
// ===================== ANATOMIE (100 questions) =====================
{subject:"anatomie",question:"Quel os ne fait PAS partie du carpe ?",options:[{text:"Scaphoïde",correct:false},{text:"Lunatum",correct:false},{text:"Cuboïde",correct:true},{text:"Trapèze",correct:false}],explanation:"Le cuboïde est un os du tarse (pied), pas du carpe (poignet). Le carpe comprend 8 os : scaphoïde, lunatum, triquétrum, pisiforme, trapèze, trapézoïde, capitatum et hamatum."},
{subject:"anatomie",question:"Le muscle deltoïde est innervé par quel nerf ?",options:[{text:"Nerf musculo-cutané",correct:false},{text:"Nerf axillaire",correct:true},{text:"Nerf radial",correct:false},{text:"Nerf médian",correct:false}],explanation:"Le nerf axillaire (C5-C6) innerve le muscle deltoïde et le petit rond. Il passe par l'espace axillaire latéral (quadrilatère de Velpeau)."},
{subject:"anatomie",question:"L'artère rénale droite passe en arrière de quelle structure ?",options:[{text:"La veine cave inférieure",correct:true},{text:"L'aorte abdominale",correct:false},{text:"La veine rénale gauche",correct:false},{text:"Le duodénum",correct:false}],explanation:"L'artère rénale droite est plus longue que la gauche et passe en arrière de la veine cave inférieure pour atteindre le rein droit. C'est un rapport anatomique classique."},
{subject:"anatomie",question:"Combien de vertèbres cervicales possède le rachis humain ?",options:[{text:"5",correct:false},{text:"7",correct:true},{text:"8",correct:false},{text:"12",correct:false}],explanation:"Le rachis cervical comporte 7 vertèbres (C1-C7). C1 est l'atlas, C2 l'axis. Attention : il y a 8 nerfs cervicaux mais seulement 7 vertèbres cervicales."},
{subject:"anatomie",question:"Le canal inguinal livre passage à quelle structure chez l'homme ?",options:[{text:"Le nerf fémoral",correct:false},{text:"L'artère fémorale",correct:false},{text:"Le cordon spermatique",correct:true},{text:"L'uretère",correct:false}],explanation:"Chez l'homme, le canal inguinal contient le cordon spermatique (comprenant le conduit déférent, les vaisseaux testiculaires et le processus vaginal). Chez la femme, il contient le ligament rond de l'utérus."},
{subject:"anatomie",question:"Quelle structure anatomique sépare le lobe droit du lobe gauche du foie ?",options:[{text:"Le ligament falciforme",correct:false},{text:"La ligne de Cantlie",correct:true},{text:"Le sillon du ligament rond",correct:false},{text:"Le ligament coronaire",correct:false}],explanation:"La ligne de Cantlie (plan passant par la veine cave inférieure et le milieu de la vésicule biliaire) sépare fonctionnellement le foie en lobe droit et gauche. Le ligament falciforme ne correspond pas à la division fonctionnelle."},
{subject:"anatomie",question:"Le nerf récurrent laryngé gauche contourne quelle structure ?",options:[{text:"L'artère sous-clavière droite",correct:false},{text:"La crosse de l'aorte",correct:true},{text:"Le tronc brachio-céphalique",correct:false},{text:"L'artère pulmonaire droite",correct:false}],explanation:"Le nerf récurrent laryngé gauche contourne la crosse de l'aorte par en dessous puis remonte dans le sillon trachéo-oesophagien. Le droit contourne l'artère sous-clavière droite."},
{subject:"anatomie",question:"Quel muscle est le principal fléchisseur de l'avant-bras sur le bras ?",options:[{text:"Biceps brachial",correct:false},{text:"Brachial",correct:true},{text:"Brachio-radial",correct:false},{text:"Triceps brachial",correct:false}],explanation:"Le muscle brachial (brachial antérieur) est le principal fléchisseur du coude. Le biceps brachial est un fléchisseur accessoire et surtout supinateur. Le brachio-radial intervient en position neutre."},
{subject:"anatomie",question:"Le foramen magnum se situe dans quel os ?",options:[{text:"L'os sphénoïde",correct:false},{text:"L'os temporal",correct:false},{text:"L'os occipital",correct:true},{text:"L'os pariétal",correct:false}],explanation:"Le foramen magnum (trou occipital) est situé dans l'os occipital. Il livre passage à la moelle allongée (bulbe rachidien), aux artères vertébrales et aux racines spinales du nerf accessoire."},
{subject:"anatomie",question:"L'artère mésentérique supérieure vascularise quelle portion du tube digestif ?",options:[{text:"De l'estomac au duodénum",correct:false},{text:"Du jéjunum au côlon transverse",correct:true},{text:"Du côlon descendant au rectum",correct:false},{text:"De l'oesophage à l'estomac",correct:false}],explanation:"L'artère mésentérique supérieure vascularise l'intestin moyen embryologique : du duodénum D3 au 2/3 droits du côlon transverse. L'artère mésentérique inférieure vascularise le reste du côlon et le rectum."},
{subject:"anatomie",question:"Quel ventricule du coeur propulse le sang dans l'artère pulmonaire ?",options:[{text:"Ventricule gauche",correct:false},{text:"Oreillette droite",correct:false},{text:"Ventricule droit",correct:true},{text:"Oreillette gauche",correct:false}],explanation:"Le ventricule droit éjecte le sang dans le tronc pulmonaire qui se divise en artères pulmonaires droite et gauche. Le ventricule gauche éjecte le sang dans l'aorte pour la circulation systémique."},
{subject:"anatomie",question:"Le plexus brachial est formé par les rameaux ventraux de quels nerfs spinaux ?",options:[{text:"C3-C7",correct:false},{text:"C5-T1",correct:true},{text:"C4-C8",correct:false},{text:"C6-T2",correct:false}],explanation:"Le plexus brachial est constitué des rameaux ventraux de C5, C6, C7, C8 et T1. Il s'organise en troncs, faisceaux puis branches terminales qui innervent le membre supérieur."},
{subject:"anatomie",question:"Quelle structure forme le plancher du 4ème ventricule ?",options:[{text:"Le cervelet",correct:false},{text:"La fosse rhomboïde",correct:true},{text:"Le thalamus",correct:false},{text:"Le corps calleux",correct:false}],explanation:"Le plancher du 4ème ventricule est la fosse rhomboïde, formée par la face dorsale du pont et de la moelle allongée. Le cervelet forme le toit du 4ème ventricule."},
{subject:"anatomie",question:"L'articulation de la hanche est de quel type ?",options:[{text:"Trochléenne",correct:false},{text:"Sphéroïde (énarthrose)",correct:true},{text:"Condylienne",correct:false},{text:"Trochoïde",correct:false}],explanation:"L'articulation coxo-fémorale est une sphéroïde (énarthrose) permettant des mouvements dans les 3 plans de l'espace. La tête du fémur s'articule avec l'acétabulum de l'os coxal."},
{subject:"anatomie",question:"Le muscle grand fessier est principalement un muscle :",options:[{text:"Fléchisseur de la hanche",correct:false},{text:"Extenseur de la hanche",correct:true},{text:"Adducteur de la hanche",correct:false},{text:"Fléchisseur du genou",correct:false}],explanation:"Le grand fessier (gluteus maximus) est le principal extenseur de la hanche. Il est essentiel pour la montée d'escaliers, le relèvement du tronc et la course. Il est innervé par le nerf glutéal inférieur."},
{subject:"anatomie",question:"Le triangle de Scarpa contient quelle artère ?",options:[{text:"Artère iliaque externe",correct:false},{text:"Artère fémorale",correct:true},{text:"Artère poplitée",correct:false},{text:"Artère tibiale antérieure",correct:false}],explanation:"Le triangle de Scarpa (triangle fémoral) contient l'artère fémorale, la veine fémorale et le nerf fémoral. L'artère fémorale est le prolongement de l'artère iliaque externe après le ligament inguinal."},
{subject:"anatomie",question:"Quel est le plus grand os sésamoïde du corps humain ?",options:[{text:"Le pisiforme",correct:false},{text:"La patella",correct:true},{text:"Le calcanéus",correct:false},{text:"L'os hyoïde",correct:false}],explanation:"La patella (rotule) est le plus grand os sésamoïde du corps humain. Elle est incluse dans le tendon du muscle quadriceps fémoral et protège l'articulation du genou."},
{subject:"anatomie",question:"Le nerf sciatique est la branche terminale de quel plexus ?",options:[{text:"Plexus lombaire",correct:false},{text:"Plexus sacral",correct:true},{text:"Plexus brachial",correct:false},{text:"Plexus cervical",correct:false}],explanation:"Le nerf sciatique (L4-S3) est la plus grosse branche terminale du plexus sacral. C'est le nerf le plus long et le plus volumineux du corps humain. Il se divise en nerf tibial et nerf fibulaire commun."},
{subject:"anatomie",question:"La veine porte hépatique est formée par la confluence de quelles veines ?",options:[{text:"Veines hépatiques et veine cave inférieure",correct:false},{text:"Veine mésentérique supérieure et veine splénique",correct:true},{text:"Veine rénale et veine surrénale",correct:false},{text:"Veines sus-hépatiques et veine ombilicale",correct:false}],explanation:"La veine porte se forme derrière le col du pancréas par la confluence de la veine mésentérique supérieure et de la veine splénique. La veine mésentérique inférieure se jette dans la veine splénique."},
{subject:"anatomie",question:"Quel os contient le rocher (partie pétreuse) ?",options:[{text:"Os sphénoïde",correct:false},{text:"Os temporal",correct:true},{text:"Os ethmoïde",correct:false},{text:"Os frontal",correct:false}],explanation:"Le rocher (partie pétreuse) est la partie la plus dense de l'os temporal. Il contient l'oreille interne (cochlée et vestibule) et le canal carotidien pour l'artère carotide interne."},
{subject:"anatomie",question:"L'appendice vermiforme se projette au point de McBurney, situé :",options:[{text:"Au tiers interne de la ligne ombilic-EIAS gauche",correct:false},{text:"Au tiers externe de la ligne ombilic-EIAS droite",correct:true},{text:"Au milieu de la ligne bi-iliaque",correct:false},{text:"Au tiers interne de la ligne ombilic-pubis",correct:false}],explanation:"Le point de McBurney se situe à la jonction du tiers externe et des deux tiers internes de la ligne reliant l'ombilic à l'épine iliaque antéro-supérieure (EIAS) droite. C'est un repère clinique pour l'appendicite."},
{subject:"anatomie",question:"Le muscle diaphragme est innervé principalement par quel nerf ?",options:[{text:"Nerf vague",correct:false},{text:"Nerf intercostal",correct:false},{text:"Nerf phrénique",correct:true},{text:"Nerf thoracique long",correct:false}],explanation:"Le nerf phrénique (C3-C4-C5) est le nerf moteur principal du diaphragme. La lésion bilatérale de ce nerf entraîne une paralysie diaphragmatique et une détresse respiratoire grave."},
{subject:"anatomie",question:"Le ligament croisé antérieur du genou empêche quel mouvement ?",options:[{text:"Le tiroir postérieur du tibia",correct:false},{text:"Le tiroir antérieur du tibia",correct:true},{text:"Le valgus du genou",correct:false},{text:"Le varus du genou",correct:false}],explanation:"Le ligament croisé antérieur (LCA) empêche la translation antérieure du tibia par rapport au fémur (tiroir antérieur). Sa rupture est fréquente en traumatologie sportive (test de Lachman positif)."},
{subject:"anatomie",question:"Quelle artère vascularise principalement le myocarde du ventricule gauche ?",options:[{text:"Artère coronaire droite",correct:false},{text:"Artère interventriculaire antérieure",correct:true},{text:"Artère circonflexe",correct:false},{text:"Artère marginale",correct:false}],explanation:"L'artère interventriculaire antérieure (IVA), branche de l'artère coronaire gauche, vascularise la majeure partie du septum interventriculaire et la paroi antérieure du ventricule gauche. Son occlusion provoque un infarctus antérieur étendu."},
{subject:"anatomie",question:"Le nerf ulnaire passe dans quel compartiment au niveau du coude ?",options:[{text:"La gouttière bicipitale médiale",correct:false},{text:"Le canal ulnaire (gouttière épitrochléo-olécranienne)",correct:true},{text:"Le tunnel carpien",correct:false},{text:"Le canal de Guyon",correct:false}],explanation:"Le nerf ulnaire passe dans la gouttière épitrochléo-olécranienne (entre l'épicondyle médial et l'olécrâne) au coude. Il est superficiel à ce niveau, ce qui explique la sensation de décharge lors d'un choc sur le coude."},
{subject:"anatomie",question:"Le muscle psoas-iliaque s'insère distalement sur :",options:[{text:"Le grand trochanter",correct:false},{text:"Le petit trochanter",correct:true},{text:"La crête iliaque",correct:false},{text:"La tubérosité ischiatique",correct:false}],explanation:"Le muscle psoas-iliaque (fusion du psoas et de l'iliaque) s'insère sur le petit trochanter du fémur. C'est le principal fléchisseur de la hanche et il participe à la rotation externe."},
{subject:"anatomie",question:"Quel nerf crânien innerve les muscles de la mastication ?",options:[{text:"Nerf facial (VII)",correct:false},{text:"Nerf trijumeau (V3)",correct:true},{text:"Nerf hypoglosse (XII)",correct:false},{text:"Nerf glosso-pharyngien (IX)",correct:false}],explanation:"Le nerf mandibulaire (V3), branche du trijumeau, innerve les muscles masticateurs (masséter, temporal, ptérygoïdiens). Le nerf facial (VII) innerve les muscles de l'expression faciale, ne pas confondre."},
{subject:"anatomie",question:"Le tronc coeliaque se divise en combien de branches principales ?",options:[{text:"2",correct:false},{text:"3",correct:true},{text:"4",correct:false},{text:"5",correct:false}],explanation:"Le tronc coeliaque (naissant de l'aorte en T12) se divise en 3 branches : l'artère gastrique gauche, l'artère splénique et l'artère hépatique commune. C'est le trépied coeliaque de Haller."},
{subject:"anatomie",question:"Le canal cholédoque résulte de la réunion de :",options:[{text:"Le canal hépatique commun et le canal cystique",correct:true},{text:"Le canal hépatique droit et le canal hépatique gauche",correct:false},{text:"Le canal pancréatique et le canal cystique",correct:false},{text:"Le canal hépatique commun et le canal de Wirsung",correct:false}],explanation:"Le canal cholédoque est formé par la réunion du canal hépatique commun (lui-même formé par les canaux hépatiques droit et gauche) et du canal cystique (drainant la vésicule biliaire)."},
{subject:"anatomie",question:"L'espace de Retzius est situé entre :",options:[{text:"Le rectum et le sacrum",correct:false},{text:"La vessie et la symphyse pubienne",correct:true},{text:"L'utérus et le rectum",correct:false},{text:"Le foie et le diaphragme",correct:false}],explanation:"L'espace de Retzius (espace rétro-pubien ou pré-vésical) est l'espace situé entre la face postérieure de la symphyse pubienne et la face antérieure de la vessie. C'est un espace chirurgical important."},
{subject:"anatomie",question:"Le noeud sino-atrial se situe dans quelle structure cardiaque ?",options:[{text:"Oreillette gauche",correct:false},{text:"Oreillette droite",correct:true},{text:"Ventricule droit",correct:false},{text:"Septum interventriculaire",correct:false}],explanation:"Le noeud sino-atrial (noeud sinusal de Keith et Flack) est situé dans la paroi de l'oreillette droite, près de l'abouchement de la veine cave supérieure. C'est le pacemaker naturel du coeur."},
{subject:"anatomie",question:"Le ménisque médial du genou est plus souvent lésé que le latéral car il est :",options:[{text:"Plus grand",correct:false},{text:"Adhérent au ligament collatéral médial",correct:true},{text:"Plus vascularisé",correct:false},{text:"Plus fin",correct:false}],explanation:"Le ménisque médial est fermement attaché au ligament collatéral médial (tibial), ce qui limite sa mobilité et le rend plus vulnérable aux lésions lors des traumatismes en valgus-rotation externe."},
{subject:"anatomie",question:"Quelle glande endocrine est située dans la selle turcique ?",options:[{text:"Glande thyroïde",correct:false},{text:"Glande pinéale",correct:false},{text:"Hypophyse",correct:true},{text:"Glande surrénale",correct:false}],explanation:"L'hypophyse (glande pituitaire) est logée dans la selle turcique de l'os sphénoïde. Elle comprend l'adénohypophyse (antérieure) et la neurohypophyse (postérieure) et joue un rôle central dans la régulation endocrinienne."},
{subject:"anatomie",question:"Le muscle quadriceps fémoral comprend combien de chefs ?",options:[{text:"3",correct:false},{text:"4",correct:true},{text:"5",correct:false},{text:"2",correct:false}],explanation:"Le quadriceps fémoral comprend 4 chefs : le droit fémoral (seul bi-articulaire), le vaste latéral, le vaste médial et le vaste intermédiaire. Ils convergent sur le tendon quadricipital puis le ligament patellaire."},
{subject:"anatomie",question:"L'artère vertébrale est une branche de quelle artère ?",options:[{text:"Artère carotide externe",correct:false},{text:"Artère sous-clavière",correct:true},{text:"Artère carotide interne",correct:false},{text:"Tronc brachio-céphalique",correct:false}],explanation:"L'artère vertébrale est la première branche de l'artère sous-clavière. Elle monte dans les foramens transversaires de C6 à C1, puis pénètre dans le crâne par le foramen magnum pour former le tronc basilaire."},
{subject:"anatomie",question:"Le nerf médian passe dans quelle structure au niveau du poignet ?",options:[{text:"Canal de Guyon",correct:false},{text:"Tunnel carpien",correct:true},{text:"Tabatière anatomique",correct:false},{text:"Gouttière du pouls",correct:false}],explanation:"Le nerf médian traverse le tunnel carpien (canal carpien) avec les tendons des fléchisseurs. Sa compression dans ce canal provoque le syndrome du canal carpien (paresthésies dans les 3 premiers doigts)."},
{subject:"anatomie",question:"La rate est un organe situé dans quel hypochondre ?",options:[{text:"Hypochondre droit",correct:false},{text:"Hypochondre gauche",correct:true},{text:"Région épigastrique",correct:false},{text:"Fosse iliaque gauche",correct:false}],explanation:"La rate est située dans l'hypochondre gauche, en regard des 9ème, 10ème et 11ème côtes. Elle est un organe lymphoïde impliqué dans la filtration du sang et la réponse immunitaire."},
{subject:"anatomie",question:"Le triangle postérieur du cou contient quelle artère importante ?",options:[{text:"Artère carotide interne",correct:false},{text:"Artère subclavière",correct:true},{text:"Artère faciale",correct:false},{text:"Artère temporale superficielle",correct:false}],explanation:"Le triangle postérieur du cou (limité par le SCM, le trapèze et la clavicule) contient la troisième portion de l'artère subclavière, le plexus brachial et le nerf accessoire (XI)."},
{subject:"anatomie",question:"Le muscle soléaire est innervé par quel nerf ?",options:[{text:"Nerf fibulaire commun",correct:false},{text:"Nerf tibial",correct:true},{text:"Nerf fémoral",correct:false},{text:"Nerf obturateur",correct:false}],explanation:"Le muscle soléaire est innervé par le nerf tibial (branche du nerf sciatique). Il fait partie du triceps sural avec les deux chefs du gastrocnémien et s'insère sur le calcanéus via le tendon d'Achille."},
{subject:"anatomie",question:"Le conduit pancréatique principal (canal de Wirsung) s'abouche dans :",options:[{text:"Le duodénum D1",correct:false},{text:"Le duodénum D2 (papille majeure)",correct:true},{text:"Le jéjunum",correct:false},{text:"L'estomac",correct:false}],explanation:"Le canal de Wirsung s'abouche dans la deuxième portion du duodénum (D2) au niveau de la papille majeure (ampoule de Vater), souvent conjointement avec le canal cholédoque."},
{subject:"anatomie",question:"Le polygone de Willis assure une anastomose entre :",options:[{text:"Les artères vertébrales uniquement",correct:false},{text:"Les systèmes carotidien et vertébro-basilaire",correct:true},{text:"Les artères méningées",correct:false},{text:"Les veines cérébrales",correct:false}],explanation:"Le polygone de Willis (cercle artériel du cerveau) anastomose les systèmes carotidien interne (antérieur) et vertébro-basilaire (postérieur) via les artères communicantes antérieure et postérieures."},
{subject:"anatomie",question:"Le muscle sartorius est le muscle le plus long du corps. Quelle est son action principale ?",options:[{text:"Extension du genou",correct:false},{text:"Flexion, abduction et rotation latérale de la hanche",correct:true},{text:"Adduction de la hanche",correct:false},{text:"Extension de la hanche",correct:false}],explanation:"Le sartorius (couturier) réalise la flexion, l'abduction et la rotation latérale de la hanche, ainsi que la flexion du genou. Il fait partie de la patte d'oie avec le gracile et le semi-tendineux."},
{subject:"anatomie",question:"L'os hyoïde est le seul os du corps qui :",options:[{text:"Ne contient pas de moelle osseuse",correct:false},{text:"Ne s'articule avec aucun autre os",correct:true},{text:"Est entièrement cartilagineux",correct:false},{text:"Se forme par ossification membraneuse",correct:false}],explanation:"L'os hyoïde est le seul os du corps humain qui ne s'articule avec aucun autre os. Il est maintenu en place par des muscles et des ligaments, et sert de point d'ancrage pour les muscles de la langue et du larynx."},
{subject:"anatomie",question:"Le dermatome C6 correspond à quelle zone cutanée ?",options:[{text:"Face médiale de l'avant-bras",correct:false},{text:"Le pouce",correct:true},{text:"L'auriculaire",correct:false},{text:"L'épaule",correct:false}],explanation:"Le dermatome C6 couvre le pouce et la face latérale de l'avant-bras. C5 correspond à la face latérale du bras, C7 aux doigts médians, C8 à l'auriculaire et à la face médiale de la main."},
{subject:"anatomie",question:"La veine cave inférieure se forme par la confluence des veines :",options:[{text:"Iliaques internes",correct:false},{text:"Iliaques communes droite et gauche",correct:true},{text:"Rénales",correct:false},{text:"Hépatiques",correct:false}],explanation:"La veine cave inférieure naît en L5 de la confluence des deux veines iliaques communes (droite et gauche). Elle remonte à droite de l'aorte et se jette dans l'oreillette droite du coeur."},
{subject:"anatomie",question:"Quel muscle assure la pronation de l'avant-bras ?",options:[{text:"Le supinateur",correct:false},{text:"Le rond pronateur",correct:true},{text:"Le biceps brachial",correct:false},{text:"L'anconé",correct:false}],explanation:"Le rond pronateur (innervé par le nerf médian) est le principal pronateur de l'avant-bras. Le carré pronateur assiste ce mouvement. Le biceps brachial et le supinateur réalisent la supination."},
{subject:"anatomie",question:"Le lobe temporal du cerveau est le siège principal de :",options:[{text:"La motricité volontaire",correct:false},{text:"L'audition et la mémoire",correct:true},{text:"La vision",correct:false},{text:"La coordination des mouvements",correct:false}],explanation:"Le lobe temporal contient le cortex auditif primaire (gyrus temporal supérieur, aire de Heschl) et l'hippocampe impliqué dans la mémoire. L'aire de Wernicke participe à la compréhension du langage."},
{subject:"anatomie",question:"Le ligament large de l'utérus contient :",options:[{text:"L'uretère uniquement",correct:false},{text:"La trompe utérine, le ligament rond et les vaisseaux utérins",correct:true},{text:"L'ovaire uniquement",correct:false},{text:"Le rectum",correct:false}],explanation:"Le ligament large est un repli péritonéal contenant la trompe utérine (dans le mésosalpinx), le ligament rond, les vaisseaux utérins et l'uretère à sa base. L'ovaire est attaché à sa face postérieure."},
{subject:"anatomie",question:"Le sinus caverneux contient quel nerf crânien dans sa paroi latérale ?",options:[{text:"Nerf optique (II)",correct:false},{text:"Nerf oculomoteur (III)",correct:true},{text:"Nerf olfactif (I)",correct:false},{text:"Nerf vague (X)",correct:false}],explanation:"La paroi latérale du sinus caverneux contient les nerfs oculomoteur (III), trochléaire (IV) et les branches V1 et V2 du trijumeau. L'artère carotide interne et le nerf abducens (VI) traversent le sinus lui-même."},
{subject:"anatomie",question:"Le muscle tibial antérieur réalise quel mouvement du pied ?",options:[{text:"Flexion plantaire et éversion",correct:false},{text:"Dorsiflexion et inversion",correct:true},{text:"Flexion plantaire et inversion",correct:false},{text:"Dorsiflexion et éversion",correct:false}],explanation:"Le tibial antérieur réalise la dorsiflexion (flexion dorsale) et l'inversion du pied. Il est innervé par le nerf fibulaire profond. Son déficit entraîne un pied tombant (steppage)."},
{subject:"anatomie",question:"Le péritoine viscéral recouvre tous les organes suivants SAUF :",options:[{text:"L'estomac",correct:false},{text:"Le jéjunum",correct:false},{text:"Les reins",correct:true},{text:"La rate",correct:false}],explanation:"Les reins sont des organes rétropéritonéaux : ils sont en arrière du péritoine et ne sont pas recouverts par le péritoine viscéral sur leur face antérieure. L'estomac, le jéjunum et la rate sont intrapéritonéaux."},
{subject:"anatomie",question:"Le fascia de Gerota entoure quel organe ?",options:[{text:"Le foie",correct:false},{text:"Le rein",correct:true},{text:"Le pancréas",correct:false},{text:"La rate",correct:false}],explanation:"Le fascia de Gerota (fascia rénal) est une enveloppe fibreuse qui entoure le rein et la glande surrénale, délimitant la loge rénale. Il a une importance chirurgicale et radiologique majeure."},
{subject:"anatomie",question:"L'artère carotide commune se divise en artères carotides interne et externe au niveau de :",options:[{text:"C3",correct:false},{text:"C4 (bord supérieur du cartilage thyroïde)",correct:true},{text:"C6",correct:false},{text:"C7",correct:false}],explanation:"La bifurcation carotidienne se situe classiquement en regard de C4, au bord supérieur du cartilage thyroïde. Le bulbe carotidien (sinus carotidien) à ce niveau contient des barorécepteurs."},
{subject:"anatomie",question:"Combien de paires de nerfs crâniens existent ?",options:[{text:"10",correct:false},{text:"12",correct:true},{text:"14",correct:false},{text:"8",correct:false}],explanation:"Il existe 12 paires de nerfs crâniens (I à XII), numérotés en chiffres romains. Ils émergent de l'encéphale (tronc cérébral principalement) et traversent les foramens de la base du crâne."},
{subject:"anatomie",question:"Le tendon d'Achille relie le triceps sural à :",options:[{text:"La patella",correct:false},{text:"Le calcanéus",correct:true},{text:"Le talus",correct:false},{text:"Le tibia",correct:false}],explanation:"Le tendon d'Achille (tendon calcanéen) relie le triceps sural (gastrocnémiens + soléaire) à la tubérosité postérieure du calcanéus. C'est le tendon le plus épais et le plus résistant du corps humain."},
{subject:"anatomie",question:"Le sillon central (scissure de Rolando) sépare :",options:[{text:"Les lobes frontal et pariétal",correct:true},{text:"Les lobes pariétal et temporal",correct:false},{text:"Les lobes frontal et temporal",correct:false},{text:"Les lobes pariétal et occipital",correct:false}],explanation:"Le sillon central sépare le lobe frontal (en avant, gyrus précentral = cortex moteur) du lobe pariétal (en arrière, gyrus postcentral = cortex somatosensoriel)."},
{subject:"anatomie",question:"La glande thyroïde est vascularisée par combien d'artères principales ?",options:[{text:"2 (1 paire)",correct:false},{text:"4 (2 paires)",correct:true},{text:"6 (3 paires)",correct:false},{text:"1 seule",correct:false}],explanation:"La thyroïde est vascularisée par 4 artères : 2 artères thyroïdiennes supérieures (branches des carotides externes) et 2 artères thyroïdiennes inférieures (branches des troncs thyro-cervicaux). Une artère thyroïdienne ima existe parfois."},
{subject:"anatomie",question:"Le muscle piriforme est un repère anatomique important car :",options:[{text:"Il divise le foramen infra-piriforme et supra-piriforme dans la région glutéale",correct:true},{text:"Il sépare les deux lobes du foie",correct:false},{text:"Il forme le plancher pelvien",correct:false},{text:"Il assure la flexion du genou",correct:false}],explanation:"Le piriforme traverse la grande incisure ischiatique et la divise en foramen supra-piriforme (nerf glutéal supérieur) et infra-piriforme (nerf sciatique, nerf glutéal inférieur, nerf pudendal). C'est un repère chirurgical clé."},
{subject:"anatomie",question:"Le cercle artériel de la base du cerveau (polygone de Willis) comprend les artères communicantes. Combien y en a-t-il ?",options:[{text:"2 (1 antérieure, 1 postérieure)",correct:false},{text:"3 (1 antérieure, 2 postérieures)",correct:true},{text:"4 (2 antérieures, 2 postérieures)",correct:false},{text:"1 antérieure seulement",correct:false}],explanation:"Le polygone de Willis comprend 3 artères communicantes : 1 artère communicante antérieure (reliant les 2 cérébrales antérieures) et 2 artères communicantes postérieures (reliant chaque carotide interne à la cérébrale postérieure correspondante)."},
{subject:"anatomie",question:"Le cartilage cricoïde est le seul cartilage du larynx qui :",options:[{text:"Est pair",correct:false},{text:"Forme un anneau complet",correct:true},{text:"Contient les cordes vocales",correct:false},{text:"Est élastique",correct:false}],explanation:"Le cartilage cricoïde est le seul cartilage laryngé formant un anneau complet (en bague à chaton). Les autres cartilages (thyroïde, épiglotte, aryténoïdes) ne forment pas d'anneau complet."},
{subject:"anatomie",question:"L'uretère croise l'artère iliaque au niveau de la bifurcation iliaque. De quel côté passe-t-il ?",options:[{text:"En avant de l'artère",correct:true},{text:"En arrière de l'artère",correct:false},{text:"En médial de l'artère",correct:false},{text:"En latéral de l'artère",correct:false}],explanation:"L'uretère croise l'artère iliaque commune (ou l'origine de l'artère iliaque externe) par sa face antérieure pour descendre dans le pelvis. C'est un rapport chirurgical essentiel à connaître."},
{subject:"anatomie",question:"Le muscle trapèze est innervé par :",options:[{text:"Le nerf dorsal de la scapula",correct:false},{text:"Le nerf accessoire (XI) et le plexus cervical",correct:true},{text:"Le nerf thoracique long",correct:false},{text:"Le nerf supra-scapulaire",correct:false}],explanation:"Le trapèze est innervé par le nerf accessoire (XI crânien) pour sa motricité et par des branches du plexus cervical (C3-C4) pour la sensibilité proprioceptive. La lésion du XI entraîne une chute de l'épaule."},
{subject:"anatomie",question:"La membrane synoviale tapisse toute l'articulation du genou SAUF :",options:[{text:"La face profonde de la capsule articulaire",correct:false},{text:"Les surfaces cartilagineuses",correct:true},{text:"Les culs-de-sac sous-quadricipitaux",correct:false},{text:"Les replis alaires",correct:false}],explanation:"La membrane synoviale ne recouvre jamais les surfaces cartilagineuses (cartilage hyalin). Elle tapisse la face interne de la capsule, les culs-de-sac et les récessus, mais s'arrête aux marges du cartilage articulaire."},
{subject:"anatomie",question:"Le muscle sterno-cléido-mastoïdien, lorsqu'il se contracte unilatéralement, entraîne :",options:[{text:"Une flexion bilatérale du cou",correct:false},{text:"Une inclinaison homolatérale et rotation controlatérale de la tête",correct:true},{text:"Une extension du cou",correct:false},{text:"Une rotation homolatérale de la tête",correct:false}],explanation:"La contraction unilatérale du SCM provoque une inclinaison de la tête du côté de la contraction et une rotation du côté opposé. Bilatéralement, il fléchit le cou. Il est innervé par le nerf accessoire (XI)."},
{subject:"anatomie",question:"Le nerf pudendal (honteux interne) passe par quel canal ?",options:[{text:"Canal inguinal",correct:false},{text:"Canal d'Alcock",correct:true},{text:"Canal fémoral",correct:false},{text:"Canal carpien",correct:false}],explanation:"Le nerf pudendal (S2-S4) emprunte le canal d'Alcock (canal pudendal) dans la paroi latérale de la fosse ischio-rectale. Il innerve le périnée et les organes génitaux externes. Sa compression peut causer une névralgie pudendale."},
{subject:"anatomie",question:"Le rein droit est situé plus bas que le rein gauche en raison de :",options:[{text:"L'aorte abdominale",correct:false},{text:"La présence du foie au-dessus",correct:true},{text:"La rate",correct:false},{text:"L'estomac",correct:false}],explanation:"Le rein droit est situé environ 2 cm plus bas que le gauche en raison de la présence volumineuse du foie dans l'hypochondre droit qui le refoule vers le bas."},
{subject:"anatomie",question:"Le muscle transverse de l'abdomen est le muscle le plus :",options:[{text:"Superficiel de la paroi abdominale",correct:false},{text:"Profond de la paroi abdominale antérolatérale",correct:true},{text:"Long de la paroi abdominale",correct:false},{text:"Vascularisé de la paroi abdominale",correct:false}],explanation:"Le transverse est le muscle le plus profond des trois muscles larges de la paroi abdominale antérolatérale (de superficiel à profond : oblique externe, oblique interne, transverse). Il joue un rôle essentiel dans la contention abdominale."},
{subject:"anatomie",question:"Quelle valve cardiaque sépare l'oreillette gauche du ventricule gauche ?",options:[{text:"Valve tricuspide",correct:false},{text:"Valve mitrale (bicuspide)",correct:true},{text:"Valve aortique",correct:false},{text:"Valve pulmonaire",correct:false}],explanation:"La valve mitrale (ou bicuspide) sépare l'oreillette gauche du ventricule gauche. Elle possède 2 feuillets (antérieur et postérieur). La valve tricuspide (3 feuillets) est du côté droit."},
{subject:"anatomie",question:"L'aire de Broca est située dans quel gyrus ?",options:[{text:"Gyrus temporal supérieur",correct:false},{text:"Gyrus frontal inférieur",correct:true},{text:"Gyrus précentral",correct:false},{text:"Gyrus angulaire",correct:false}],explanation:"L'aire de Broca (aire 44-45 de Brodmann) est située dans le gyrus frontal inférieur de l'hémisphère dominant (gauche chez les droitiers). Sa lésion provoque une aphasie motrice (de Broca) : le patient comprend mais ne peut pas s'exprimer."},
{subject:"anatomie",question:"Les glandes surrénales sont situées au pôle supérieur des reins. La médullosurrénale sécrète :",options:[{text:"Le cortisol",correct:false},{text:"L'aldostérone",correct:false},{text:"Les catécholamines (adrénaline, noradrénaline)",correct:true},{text:"Les androgènes",correct:false}],explanation:"La médullosurrénale sécrète les catécholamines (adrénaline 80%, noradrénaline 20%). Le cortisol et l'aldostérone sont produits par le cortex surrénalien (corticosurrénale), respectivement par la zone fasciculée et la zone glomérulée."},
{subject:"anatomie",question:"Le tendon du muscle long biceps passe dans quel sillon de l'humérus ?",options:[{text:"Sillon intertuberculaire (gouttière bicipitale)",correct:true},{text:"Sillon du nerf radial",correct:false},{text:"Sillon delto-pectoral",correct:false},{text:"Gouttière olécranienne",correct:false}],explanation:"Le tendon du long biceps chemine dans le sillon intertuberculaire (entre les tubercules majeur et mineur de l'humérus). Ce trajet intra-articulaire puis extra-articulaire le rend vulnérable aux tendinopathies et aux luxations."},
{subject:"anatomie",question:"Le plexus lombaire est constitué des rameaux ventraux de :",options:[{text:"L1-L4",correct:true},{text:"L2-L5",correct:false},{text:"L3-S1",correct:false},{text:"T12-L3",correct:false}],explanation:"Le plexus lombaire est formé des rameaux ventraux de L1 à L4 (avec parfois une contribution de T12). Ses branches principales sont les nerfs fémoral (L2-L4) et obturateur (L2-L4)."},
{subject:"anatomie",question:"L'estomac est fixé en haut par quel ligament ?",options:[{text:"Le ligament gastro-colique",correct:false},{text:"Le ligament gastro-phrénique",correct:true},{text:"Le ligament gastro-splénique",correct:false},{text:"Le petit omentum",correct:false}],explanation:"Le ligament gastro-phrénique fixe le fundus gastrique au diaphragme. Le petit omentum relie la petite courbure au foie, le ligament gastro-splénique relie la grande courbure à la rate, et le ligament gastro-colique au côlon transverse."},
{subject:"anatomie",question:"Le muscle dentelé antérieur est innervé par :",options:[{text:"Le nerf thoracique long (de Charles Bell)",correct:true},{text:"Le nerf thoraco-dorsal",correct:false},{text:"Le nerf pectoral latéral",correct:false},{text:"Le nerf supra-scapulaire",correct:false}],explanation:"Le nerf thoracique long (C5-C7) innerve le muscle dentelé antérieur. Sa paralysie provoque un décollement de la scapula (scapula alata) visible lors de la poussée contre un mur."},
{subject:"anatomie",question:"La citerne chyleuse (citerne de Pecquet) est l'origine de quel canal lymphatique ?",options:[{text:"Le canal lymphatique droit",correct:false},{text:"Le canal thoracique",correct:true},{text:"Le canal inguinal",correct:false},{text:"Le canal de Nuck",correct:false}],explanation:"La citerne chyleuse (ou citerne de Pecquet), située en regard de L1-L2, est l'origine du canal thoracique. Ce dernier draine la lymphe de la majeure partie du corps et se jette dans le confluent veineux jugulo-subclavier gauche."},
{subject:"anatomie",question:"Quel os forme la partie médiale de l'orbite ?",options:[{text:"L'os zygomatique",correct:false},{text:"L'os ethmoïde (lame orbitaire)",correct:true},{text:"L'os frontal",correct:false},{text:"L'os temporal",correct:false}],explanation:"La paroi médiale de l'orbite est formée principalement par la lame orbitaire de l'ethmoïde (os papyracé, très fin), complétée par l'os lacrymal en avant. C'est la paroi la plus fragile de l'orbite."},
{subject:"anatomie",question:"La corde du tympan est une branche de quel nerf crânien ?",options:[{text:"Nerf trijumeau (V)",correct:false},{text:"Nerf facial (VII)",correct:true},{text:"Nerf glosso-pharyngien (IX)",correct:false},{text:"Nerf vague (X)",correct:false}],explanation:"La corde du tympan est une branche du nerf facial (VII). Elle traverse la caisse du tympan et rejoint le nerf lingual pour véhiculer le goût des 2/3 antérieurs de la langue et l'innervation des glandes submandibulaire et sublinguale."},
{subject:"anatomie",question:"La voûte crânienne est constituée de combien d'os principaux ?",options:[{text:"6",correct:false},{text:"8",correct:true},{text:"4",correct:false},{text:"10",correct:false}],explanation:"Le crâne est constitué de 8 os : frontal (1), pariétaux (2), temporaux (2), occipital (1), sphénoïde (1) et ethmoïde (1). La voûte (calvaria) est formée principalement par le frontal, les pariétaux et l'occipital."},
{subject:"anatomie",question:"Le ligament inguinal (arcade crurale de Poupart) relie :",options:[{text:"Les deux épines iliaques antéro-supérieures",correct:false},{text:"L'EIAS au tubercule pubien",correct:true},{text:"L'EIAS à la symphyse pubienne",correct:false},{text:"La crête iliaque au sacrum",correct:false}],explanation:"Le ligament inguinal s'étend de l'épine iliaque antéro-supérieure (EIAS) au tubercule pubien. C'est le bord inférieur de l'aponévrose de l'oblique externe et la limite supérieure du triangle fémoral."},
{subject:"anatomie",question:"Le muscle obturateur interne sort du pelvis par quelle échancrure ?",options:[{text:"Grande incisure ischiatique",correct:false},{text:"Petite incisure ischiatique",correct:true},{text:"Foramen obturé",correct:false},{text:"Foramen ischiatique",correct:false}],explanation:"L'obturateur interne naît de la face interne de la membrane obturatrice, sort du pelvis par la petite incisure ischiatique et se termine sur le grand trochanter. Il est rotateur latéral de la hanche."},
{subject:"anatomie",question:"Le muscle releveur de l'anus forme la majeure partie de quel plancher ?",options:[{text:"Le plancher buccal",correct:false},{text:"Le diaphragme pelvien",correct:true},{text:"Le plancher orbitaire",correct:false},{text:"Le plancher nasal",correct:false}],explanation:"Le muscle releveur de l'anus (avec ses faisceaux pubo-coccygien, pubo-rectal et ilio-coccygien) constitue la majeure partie du diaphragme pelvien. Il soutient les organes pelviens et participe à la continence."},
{subject:"anatomie",question:"L'artère brachiale se divise en artères radiale et ulnaire au niveau de :",options:[{text:"L'aisselle",correct:false},{text:"La fosse cubitale (pli du coude)",correct:true},{text:"Le poignet",correct:false},{text:"Le milieu du bras",correct:false}],explanation:"L'artère brachiale (humérale) se divise en artères radiale et ulnaire dans la fosse cubitale, en regard du col du radius. L'artère brachiale est celle utilisée pour mesurer la pression artérielle au bras."},
{subject:"anatomie",question:"Le nerf phrénique passe en avant de quel muscle au niveau du cou ?",options:[{text:"Le trapèze",correct:false},{text:"Le scalène antérieur",correct:true},{text:"Le SCM",correct:false},{text:"Le scalène moyen",correct:false}],explanation:"Le nerf phrénique descend sur la face antérieure du muscle scalène antérieur. C'est un repère anatomique important : le nerf phrénique est en avant du scalène antérieur, tandis que le plexus brachial est en arrière."},
{subject:"anatomie",question:"Le duodénum est divisé en combien de portions ?",options:[{text:"2",correct:false},{text:"3",correct:false},{text:"4",correct:true},{text:"5",correct:false}],explanation:"Le duodénum comprend 4 portions : D1 (supérieure/bulbe), D2 (descendante, reçoit le cholédoque et le Wirsung), D3 (horizontale, croisée par l'AMS) et D4 (ascendante, se termine à l'angle de Treitz)."},
{subject:"anatomie",question:"Le muscle subscapulaire est un rotateur :",options:[{text:"Latéral de l'épaule",correct:false},{text:"Médial de l'épaule",correct:true},{text:"Il ne participe pas à la rotation",correct:false},{text:"Il est fléchisseur uniquement",correct:false}],explanation:"Le subscapulaire est le seul muscle de la coiffe des rotateurs qui réalise la rotation médiale (interne) de l'épaule. Les autres muscles de la coiffe (supra-épineux, infra-épineux, petit rond) sont rotateurs latéraux ou abducteurs."},
{subject:"anatomie",question:"Les corps vertébraux sont reliés entre eux en avant par quel ligament ?",options:[{text:"Le ligament jaune",correct:false},{text:"Le ligament longitudinal antérieur",correct:true},{text:"Le ligament inter-épineux",correct:false},{text:"Le ligament nuchal",correct:false}],explanation:"Le ligament longitudinal antérieur tapisse la face antérieure des corps vertébraux sur toute la hauteur du rachis. Le ligament longitudinal postérieur est sur la face postérieure des corps vertébraux, dans le canal vertébral."},
{subject:"anatomie",question:"Le nerf fémoral est formé par les racines :",options:[{text:"L1-L2",correct:false},{text:"L2-L3-L4",correct:true},{text:"L4-L5-S1",correct:false},{text:"L3-L4-L5",correct:false}],explanation:"Le nerf fémoral (crural) est formé des racines L2, L3 et L4. Il passe sous le ligament inguinal dans la lacune musculaire et innerve le quadriceps (extension du genou) et donne le nerf saphène (sensibilité face médiale de jambe)."},
{subject:"anatomie",question:"Le tronc sympathique cervical comprend combien de ganglions ?",options:[{text:"2",correct:false},{text:"3",correct:true},{text:"4",correct:false},{text:"5",correct:false}],explanation:"Le tronc sympathique cervical comprend 3 ganglions : supérieur (le plus volumineux), moyen (inconstant) et inférieur (souvent fusionné avec T1 pour former le ganglion stellaire/cervico-thoracique)."},
{subject:"anatomie",question:"L'innervation sensitive de la face est assurée principalement par :",options:[{text:"Le nerf facial (VII)",correct:false},{text:"Le nerf trijumeau (V)",correct:true},{text:"Le nerf accessoire (XI)",correct:false},{text:"Le nerf hypoglosse (XII)",correct:false}],explanation:"Le nerf trijumeau (V) assure l'innervation sensitive de la face via ses 3 branches : V1 ophtalmique (front, paupière supérieure), V2 maxillaire (joue, lèvre supérieure), V3 mandibulaire (menton, lèvre inférieure)."},
{subject:"anatomie",question:"Le foramen ovale du coeur foetal se ferme après la naissance pour former :",options:[{text:"Le ligament artériel",correct:false},{text:"La fosse ovale",correct:true},{text:"Le ligament rond",correct:false},{text:"La valve de Thébésius",correct:false}],explanation:"Après la naissance, le foramen ovale (communication inter-auriculaire foetale) se ferme pour former la fosse ovale dans le septum interatrial. Le ligament artériel est le vestige du canal artériel."},
{subject:"anatomie",question:"La bandelette de Maissiat (tractus ilio-tibial) est un épaississement de :",options:[{text:"L'aponévrose du quadriceps",correct:false},{text:"Le fascia lata",correct:true},{text:"Le ligament collatéral latéral",correct:false},{text:"Le ligament patellaire",correct:false}],explanation:"La bandelette ilio-tibiale (de Maissiat) est un épaississement du fascia lata sur la face latérale de la cuisse. Elle reçoit les insertions du tenseur du fascia lata et du grand fessier et se termine sur le tubercule de Gerdy du tibia."},
{subject:"anatomie",question:"Le muscle crémaster est une dépendance de quel muscle abdominal ?",options:[{text:"Le transverse de l'abdomen",correct:false},{text:"L'oblique interne",correct:true},{text:"L'oblique externe",correct:false},{text:"Le droit de l'abdomen",correct:false}],explanation:"Le crémaster est formé par des fibres issues du muscle oblique interne de l'abdomen. Il engaine le cordon spermatique et le testicule, et assure le réflexe crémastérien (ascension du testicule lors de la stimulation de la face médiale de la cuisse)."},

// ===================== CHIMIE / BIOCHIMIE (100 questions) =====================
{subject:"chimie",question:"Quel est le nombre quantique principal de la couche M ?",options:[{text:"1",correct:false},{text:"2",correct:false},{text:"3",correct:true},{text:"4",correct:false}],explanation:"Les couches K, L, M, N correspondent aux nombres quantiques principaux n = 1, 2, 3, 4 respectivement. La couche M peut contenir jusqu'à 2n² = 18 électrons."},
{subject:"chimie",question:"Quelle est la géométrie d'une molécule de type AX₄ selon la théorie VSEPR ?",options:[{text:"Plane carrée",correct:false},{text:"Tétraédrique",correct:true},{text:"Pyramidale à base triangulaire",correct:false},{text:"Linéaire",correct:false}],explanation:"AX₄ (4 paires liantes, 0 paire libre) adopte une géométrie tétraédrique avec des angles de 109°28'. Exemples : CH₄, CCl₄."},
{subject:"chimie",question:"Dans la classification périodique, l'électronégativité augmente :",options:[{text:"De droite à gauche et de haut en bas",correct:false},{text:"De gauche à droite et de bas en haut",correct:true},{text:"De gauche à droite et de haut en bas",correct:false},{text:"Elle reste constante dans une période",correct:false}],explanation:"L'électronégativité (échelle de Pauling) augmente de gauche à droite dans une période (augmentation de Z*) et de bas en haut dans un groupe (diminution du rayon). Le fluor est l'élément le plus électronégatif (3,98)."},
{subject:"chimie",question:"Quel type de liaison est formé entre Na et Cl dans NaCl ?",options:[{text:"Covalente pure",correct:false},{text:"Covalente polarisée",correct:false},{text:"Ionique",correct:true},{text:"Métallique",correct:false}],explanation:"La différence d'électronégativité ΔEN entre Na (0,93) et Cl (3,16) est de 2,23 (> 1,7), ce qui correspond à une liaison ionique. NaCl forme un réseau cristallin ionique cubique faces centrées."},
{subject:"chimie",question:"Quel est l'hybridation du carbone dans l'éthylène (C₂H₄) ?",options:[{text:"sp",correct:false},{text:"sp²",correct:true},{text:"sp³",correct:false},{text:"sp³d",correct:false}],explanation:"Dans l'éthylène, chaque carbone est hybridé sp² (3 liaisons σ : 2 C-H + 1 C-C) avec un orbital p non hybridé perpendiculaire formant la liaison π. La géométrie est plane trigonale (120°)."},
{subject:"chimie",question:"La réaction de saponification est une réaction entre :",options:[{text:"Un acide et un alcool",correct:false},{text:"Un ester et une base forte",correct:true},{text:"Un acide et une amine",correct:false},{text:"Un alcool et un aldéhyde",correct:false}],explanation:"La saponification est l'hydrolyse basique (irréversible) d'un ester par NaOH ou KOH, donnant un carboxylate (savon) et un alcool. C'est une réaction totale, contrairement à l'hydrolyse acide (équilibre)."},
{subject:"chimie",question:"Un carbone asymétrique est un carbone lié à :",options:[{text:"4 substituants identiques",correct:false},{text:"4 substituants différents",correct:true},{text:"3 substituants et un doublet libre",correct:false},{text:"2 substituants et 2 hydrogènes",correct:false}],explanation:"Un carbone asymétrique (centre stéréogène) porte 4 substituants tous différents. Il génère de la chiralité : 2 énantiomères (images l'un de l'autre dans un miroir, non superposables)."},
{subject:"chimie",question:"Quel est le pH d'une solution d'HCl 0,01 M ?",options:[{text:"1",correct:false},{text:"2",correct:true},{text:"3",correct:false},{text:"0,01",correct:false}],explanation:"HCl est un acide fort totalement dissocié : [H₃O⁺] = C = 0,01 = 10⁻² M. pH = -log[H₃O⁺] = -log(10⁻²) = 2."},
{subject:"chimie",question:"La constante d'Avogadro vaut approximativement :",options:[{text:"6,02 × 10²³ mol⁻¹",correct:true},{text:"6,02 × 10²⁰ mol⁻¹",correct:false},{text:"1,38 × 10⁻²³ J/K",correct:false},{text:"8,314 J/(mol·K)",correct:false}],explanation:"NA = 6,022 × 10²³ mol⁻¹ est le nombre d'entités dans une mole. 1,38 × 10⁻²³ est la constante de Boltzmann kB, et 8,314 est la constante des gaz parfaits R = NA × kB."},
{subject:"chimie",question:"Dans une réaction d'oxydoréduction, l'oxydant :",options:[{text:"Perd des électrons",correct:false},{text:"Gagne des électrons",correct:true},{text:"Perd des protons",correct:false},{text:"Ne change pas de degré d'oxydation",correct:false}],explanation:"L'oxydant gagne des électrons (il est réduit). Le réducteur perd des électrons (il est oxydé). Moyen mnémotechnique : OGA (Oxydant Gagne e⁻) / RPE (Réducteur Perd e⁻)."},
{subject:"chimie",question:"La configuration absolue R ou S est déterminée par les règles de :",options:[{text:"Hund",correct:false},{text:"Cahn-Ingold-Prelog",correct:true},{text:"Markovnikov",correct:false},{text:"Le Chatelier",correct:false}],explanation:"Les règles CIP (Cahn-Ingold-Prelog) classent les substituants par priorité (numéro atomique décroissant). Si le plus petit est en arrière et que le sens de rotation des priorités est horaire → R, antihoraire → S."},
{subject:"chimie",question:"Quel est le produit principal de l'addition de HBr sur le propène selon la règle de Markovnikov ?",options:[{text:"1-bromopropane",correct:false},{text:"2-bromopropane",correct:true},{text:"3-bromopropane",correct:false},{text:"Propan-2-ol",correct:false}],explanation:"Markovnikov : H se fixe sur le carbone le plus hydrogéné, Br sur le plus substitué. Sur CH₃-CH=CH₂, H va sur CH₂ et Br sur CH → CH₃-CHBr-CH₃ (2-bromopropane)."},
{subject:"chimie",question:"L'énergie d'ionisation d'un atome correspond à :",options:[{text:"L'énergie libérée lors de la capture d'un électron",correct:false},{text:"L'énergie nécessaire pour arracher un électron à l'atome gazeux",correct:true},{text:"L'énergie de la liaison chimique",correct:false},{text:"L'énergie du photon émis lors d'une transition",correct:false}],explanation:"L'énergie d'ionisation (EI) est l'énergie minimale pour arracher l'électron le plus faiblement lié d'un atome gazeux à l'état fondamental : A(g) → A⁺(g) + e⁻. EI augmente dans une période (de gauche à droite)."},
{subject:"chimie",question:"Quel acide aminé possède un groupement thiol (-SH) dans sa chaîne latérale ?",options:[{text:"Sérine",correct:false},{text:"Cystéine",correct:true},{text:"Méthionine",correct:false},{text:"Thréonine",correct:false}],explanation:"La cystéine possède un -CH₂-SH. Deux cystéines peuvent former un pont disulfure (-S-S-) stabilisant la structure tertiaire des protéines. La méthionine contient aussi du soufre mais sous forme thioéther (-S-CH₃)."},
{subject:"chimie",question:"L'effet inductif donneur (+I) est caractéristique de quel type de groupement ?",options:[{text:"Les groupements alkyles",correct:true},{text:"Les halogènes",correct:false},{text:"Le groupement nitro (-NO₂)",correct:false},{text:"Le groupement carbonyle (C=O)",correct:false}],explanation:"Les groupements alkyles sont +I (donneurs par effet inductif) car ils libèrent de la densité électronique. Les halogènes, -NO₂, -COOH, C=O sont -I (attracteurs). Plus la chaîne carbonée est longue, plus l'effet +I est important."},
{subject:"chimie",question:"La loi de Beer-Lambert relie l'absorbance à :",options:[{text:"La température et la pression",correct:false},{text:"La concentration, l'épaisseur et le coefficient d'extinction molaire",correct:true},{text:"La masse molaire et le volume",correct:false},{text:"Le pH et la force ionique",correct:false}],explanation:"A = ε × l × C, où A est l'absorbance, ε le coefficient d'extinction molaire (L·mol⁻¹·cm⁻¹), l l'épaisseur de la cuve (cm) et C la concentration (mol/L). Valable pour les solutions diluées."},
{subject:"chimie",question:"Km dans l'équation de Michaelis-Menten représente :",options:[{text:"La vitesse maximale de la réaction",correct:false},{text:"La concentration en substrat pour laquelle v = Vmax/2",correct:true},{text:"La constante d'équilibre de la réaction",correct:false},{text:"Le nombre de turnover de l'enzyme",correct:false}],explanation:"Km (constante de Michaelis) est la concentration en substrat [S] pour laquelle la vitesse est la moitié de Vmax. Un Km faible indique une forte affinité enzyme-substrat. v = Vmax × [S] / (Km + [S])."},
{subject:"chimie",question:"Un inhibiteur compétitif de l'enzyme :",options:[{text:"Diminue Vmax sans modifier Km",correct:false},{text:"Augmente Km apparent sans modifier Vmax",correct:true},{text:"Diminue Vmax et Km",correct:false},{text:"N'a aucun effet sur Km et Vmax",correct:false}],explanation:"L'inhibiteur compétitif se lie au site actif (compétition avec le substrat). Km apparent augmente (il faut plus de substrat pour atteindre Vmax/2), mais Vmax reste inchangé car l'inhibition peut être levée par excès de substrat."},
{subject:"chimie",question:"La liaison peptidique est une liaison de type :",options:[{text:"Ester",correct:false},{text:"Amide",correct:true},{text:"Éther",correct:false},{text:"Thioester",correct:false}],explanation:"La liaison peptidique est une liaison amide (-CO-NH-) formée par condensation entre le -COOH d'un acide aminé et le -NH₂ du suivant, avec élimination d'H₂O. Elle est plane et rigide (caractère partiel de double liaison C-N)."},
{subject:"chimie",question:"L'ATP est hydrolysé en ADP + Pi. Cette réaction est :",options:[{text:"Endergonique (ΔG > 0)",correct:false},{text:"Exergonique (ΔG < 0)",correct:true},{text:"À l'équilibre (ΔG = 0)",correct:false},{text:"Endothermique",correct:false}],explanation:"L'hydrolyse de l'ATP est exergonique : ΔG°' = -30,5 kJ/mol. L'énergie libérée provient de la déstabilisation des charges négatives rapprochées sur les phosphates et de la stabilisation par résonance des produits."},
{subject:"chimie",question:"Quel cofacteur est le transporteur universel d'électrons dans les réactions d'oxydoréduction cellulaires ?",options:[{text:"ATP",correct:false},{text:"NAD⁺/NADH",correct:true},{text:"CoA",correct:false},{text:"Biotine",correct:false}],explanation:"NAD⁺ (nicotinamide adénine dinucléotide) est réduit en NADH + H⁺ en acceptant 2 électrons et 1 proton. C'est le principal collecteur d'électrons dans le catabolisme. Les électrons du NADH alimentent la chaîne respiratoire."},
{subject:"chimie",question:"Le cycle de Krebs se déroule dans :",options:[{text:"Le cytoplasme",correct:false},{text:"La matrice mitochondriale",correct:true},{text:"La membrane interne mitochondriale",correct:false},{text:"Le réticulum endoplasmique",correct:false}],explanation:"Le cycle de Krebs (cycle de l'acide citrique) se déroule dans la matrice mitochondriale. Il oxyde l'acétyl-CoA en 2 CO₂, produisant 3 NADH, 1 FADH₂ et 1 GTP par tour de cycle."},
{subject:"chimie",question:"La β-oxydation des acides gras produit principalement :",options:[{text:"Du glucose",correct:false},{text:"De l'acétyl-CoA, du NADH et du FADH₂",correct:true},{text:"Du lactate",correct:false},{text:"De l'urée",correct:false}],explanation:"La β-oxydation (hélice de Lynen) dégrade les AG par coupures successives de 2 carbones, libérant à chaque tour 1 acétyl-CoA + 1 NADH + 1 FADH₂. Un AG à 16C (palmitate) donne 8 acétyl-CoA en 7 tours."},
{subject:"chimie",question:"Quel est le nombre d'oxydation du manganèse dans KMnO₄ ?",options:[{text:"+4",correct:false},{text:"+5",correct:false},{text:"+7",correct:true},{text:"+2",correct:false}],explanation:"Dans KMnO₄ : K = +1, O = -2. Charge totale = 0. Donc +1 + Mn + 4×(-2) = 0 → Mn = +7. Le permanganate est un oxydant puissant, réduit en Mn²⁺ (milieu acide) ou MnO₂ (milieu neutre)."},
{subject:"chimie",question:"Quelle est la formule de l'enthalpie libre de Gibbs ?",options:[{text:"ΔG = ΔH + TΔS",correct:false},{text:"ΔG = ΔH - TΔS",correct:true},{text:"ΔG = ΔU - TΔS",correct:false},{text:"ΔG = -TΔS",correct:false}],explanation:"ΔG = ΔH - TΔS. Une réaction est spontanée si ΔG < 0. ΔH < 0 (exothermique) et ΔS > 0 (augmentation du désordre) favorisent la spontanéité. À l'équilibre, ΔG = 0."},
{subject:"chimie",question:"Un diastéréoisomère est :",options:[{text:"L'image miroir non superposable d'une molécule chirale",correct:false},{text:"Un stéréoisomère qui n'est PAS l'image miroir",correct:true},{text:"Un isomère de constitution",correct:false},{text:"Un conformère",correct:false}],explanation:"Les diastéréoisomères sont des stéréoisomères qui ne sont PAS énantiomères (pas images miroir). Exemples : isomères E/Z, épimères, anomères. Ils ont des propriétés physiques et chimiques différentes."},
{subject:"chimie",question:"Le glucose est un :",options:[{text:"Cétohexose",correct:false},{text:"Aldohexose",correct:true},{text:"Aldopentose",correct:false},{text:"Cétopentose",correct:false}],explanation:"Le glucose (C₆H₁₂O₆) est un aldohexose : aldéhyde (aldo-) à 6 carbones (-hexose). Le fructose est un cétohexose. Le ribose est un aldopentose. En solution, le glucose existe majoritairement sous forme cyclique (pyranose)."},
{subject:"chimie",question:"La liaison glycosidique α(1→4) est caractéristique de :",options:[{text:"Le saccharose",correct:false},{text:"L'amylose (amidon)",correct:true},{text:"La cellulose",correct:false},{text:"Le lactose",correct:false}],explanation:"L'amylose (composant linéaire de l'amidon) est un polymère de glucose relié par des liaisons α(1→4). La cellulose utilise des liaisons β(1→4), non hydrolysables par l'amylase humaine. Le glycogène a des α(1→4) et des α(1→6) aux branchements."},
{subject:"chimie",question:"Quel acide aminé est le seul à avoir une chaîne latérale cyclique intégrée à la chaîne principale (iminoacide) ?",options:[{text:"Histidine",correct:false},{text:"Tryptophane",correct:false},{text:"Proline",correct:true},{text:"Phénylalanine",correct:false}],explanation:"La proline est un iminoacide : sa chaîne latérale forme un cycle avec l'azote de la fonction amine. Cette structure rigide impose des contraintes conformationnelles et brise souvent les hélices α."},
{subject:"chimie",question:"La structure quaternaire d'une protéine correspond à :",options:[{text:"La séquence en acides aminés",correct:false},{text:"Les hélices α et feuillets β",correct:false},{text:"Le repliement 3D d'une chaîne",correct:false},{text:"L'association de plusieurs sous-unités",correct:true}],explanation:"La structure quaternaire est l'arrangement spatial de plusieurs chaînes polypeptidiques (sous-unités) formant un complexe fonctionnel. Exemple : l'hémoglobine (α₂β₂ = 4 sous-unités). Toutes les protéines n'ont pas de structure quaternaire."},
{subject:"chimie",question:"Quel est le pH isoélectrique (pI) d'un acide aminé neutre dont pKa₁ = 2,3 et pKa₂ = 9,7 ?",options:[{text:"2,3",correct:false},{text:"6,0",correct:true},{text:"9,7",correct:false},{text:"12,0",correct:false}],explanation:"Pour un AA neutre, pI = (pKa₁ + pKa₂) / 2 = (2,3 + 9,7) / 2 = 6,0. Au pI, la charge nette est nulle (forme zwitterionique). L'AA ne migre pas en électrophorèse à ce pH."},
{subject:"chimie",question:"La dénaturation d'une protéine détruit :",options:[{text:"La structure primaire",correct:false},{text:"Les structures secondaire, tertiaire et quaternaire",correct:true},{text:"Uniquement les ponts disulfures",correct:false},{text:"Les liaisons peptidiques",correct:false}],explanation:"La dénaturation (chaleur, pH extrême, agents chaotropiques) détruit les structures supérieures (II, III, IV) mais conserve la structure primaire (séquence en AA). Les liaisons peptidiques covalentes ne sont pas rompues."},
{subject:"chimie",question:"Le NADH cède ses électrons à la chaîne respiratoire au niveau du :",options:[{text:"Complexe II",correct:false},{text:"Complexe I",correct:true},{text:"Complexe III",correct:false},{text:"Complexe IV",correct:false}],explanation:"Le NADH cède ses 2 électrons au complexe I (NADH déshydrogénase). Le FADH₂ les cède au complexe II (succinate déshydrogénase). Les électrons transitent ensuite par le coenzyme Q, le complexe III, le cytochrome c et enfin le complexe IV (cytochrome c oxydase)."},
{subject:"chimie",question:"Combien de molécules d'ATP sont produites (rendement net) par la glycolyse à partir d'un glucose ?",options:[{text:"4",correct:false},{text:"2",correct:true},{text:"36",correct:false},{text:"8",correct:false}],explanation:"La glycolyse produit 4 ATP bruts mais en consomme 2 (hexokinase et PFK-1), soit un rendement net de 2 ATP + 2 NADH + 2 pyruvates. Elle se déroule dans le cytoplasme et ne nécessite pas d'O₂."},
{subject:"chimie",question:"Quel est le produit de la fermentation lactique ?",options:[{text:"Éthanol + CO₂",correct:false},{text:"Lactate",correct:true},{text:"Acétaldéhyde",correct:false},{text:"Acétyl-CoA",correct:false}],explanation:"La fermentation lactique réduit le pyruvate en lactate par la lactate déshydrogénase (LDH), régénérant le NAD⁺ nécessaire à la glycolyse en anaérobie. La fermentation alcoolique (levures) produit éthanol + CO₂."},
{subject:"chimie",question:"L'hémoglobine fixe l'oxygène de manière :",options:[{text:"Linéaire (non coopérative)",correct:false},{text:"Sigmoïde (coopérative)",correct:true},{text:"Hyperbolique",correct:false},{text:"Exponentielle",correct:false}],explanation:"La courbe de saturation de l'Hb est sigmoïde (S), reflétant la coopérativité positive : la fixation d'un O₂ augmente l'affinité des autres sous-unités. La myoglobine (monomère) a une courbe hyperbolique (non coopérative)."},
{subject:"chimie",question:"L'effet Bohr décrit :",options:[{text:"L'augmentation de l'affinité de l'Hb pour O₂ quand le pH diminue",correct:false},{text:"La diminution de l'affinité de l'Hb pour O₂ quand le pH diminue ou la pCO₂ augmente",correct:true},{text:"La fixation du CO sur l'Hb",correct:false},{text:"La courbe de dissociation de la myoglobine",correct:false}],explanation:"L'effet Bohr : ↓pH ou ↑pCO₂ → décalage à droite de la courbe de dissociation → ↓affinité pour O₂ → libération facilitée d'O₂ dans les tissus actifs (métaboliquement acides). C'est un mécanisme adaptatif essentiel."},
{subject:"chimie",question:"Un acide aminé à chaîne latérale chargée positivement à pH 7,4 :",options:[{text:"Aspartate",correct:false},{text:"Glutamate",correct:false},{text:"Lysine",correct:true},{text:"Leucine",correct:false}],explanation:"La lysine (pKa chaîne latérale ≈ 10,5) est protonée (-NH₃⁺) à pH 7,4 → charge positive. L'arginine et l'histidine sont aussi basiques. L'aspartate et le glutamate sont chargés négativement à pH 7,4."},
{subject:"chimie",question:"La néoglucogenèse se déroule principalement dans quel organe ?",options:[{text:"Le muscle",correct:false},{text:"Le cerveau",correct:false},{text:"Le foie",correct:true},{text:"Le tissu adipeux",correct:false}],explanation:"La néoglucogenèse (synthèse de glucose à partir de précurseurs non glucidiques : lactate, alanine, glycérol) se déroule principalement dans le foie (90%) et accessoirement dans le rein. Elle maintient la glycémie à jeun."},
{subject:"chimie",question:"L'insuline favorise :",options:[{text:"La glycogénolyse hépatique",correct:false},{text:"La glycogénogenèse et la lipogenèse",correct:true},{text:"La néoglucogenèse",correct:false},{text:"La lipolyse",correct:false}],explanation:"L'insuline est l'hormone hypoglycémiante : elle stimule le stockage (glycogénogenèse, lipogenèse, protéosynthèse) et inhibe la mobilisation des réserves (glycogénolyse, néoglucogenèse, lipolyse). Le glucagon a les effets opposés."},
{subject:"chimie",question:"Quel est le nombre de liaisons sigma (σ) dans l'éthyne (acétylène, C₂H₂) ?",options:[{text:"2",correct:false},{text:"3",correct:true},{text:"4",correct:false},{text:"5",correct:false}],explanation:"C₂H₂ : 1 liaison σ C-C + 2 liaisons π C-C + 2 liaisons σ C-H = 3 liaisons σ au total. La triple liaison contient 1σ + 2π. Chaque C est hybridé sp (géométrie linéaire, angle 180°)."},
{subject:"chimie",question:"Le tampon le plus efficace en biologie à pH 7,4 est basé sur :",options:[{text:"Acide acétique/acétate (pKa = 4,75)",correct:false},{text:"H₂CO₃/HCO₃⁻ (pKa = 6,1) couplé à la ventilation pulmonaire",correct:true},{text:"NH₄⁺/NH₃ (pKa = 9,25)",correct:false},{text:"HCl/NaCl",correct:false}],explanation:"Le tampon bicarbonate (H₂CO₃/HCO₃⁻) est le principal tampon du sang, même si le pH (7,4) est loin du pKa (6,1). Son efficacité tient à sa nature 'ouverte' : le CO₂ est évacué par la ventilation → déplace l'équilibre."},
{subject:"chimie",question:"Un acide gras saturé a :",options:[{text:"Au moins une double liaison C=C",correct:false},{text:"Aucune double liaison C=C",correct:true},{text:"Un cycle aromatique",correct:false},{text:"Toujours un nombre impair de carbones",correct:false}],explanation:"Les AG saturés n'ont aucune double liaison C=C (chaîne 'saturée' en hydrogène). Exemples : acide palmitique (C16:0), stéarique (C18:0). Les AG insaturés ont ≥ 1 double liaison (oléique C18:1, linoléique C18:2)."},
{subject:"chimie",question:"Le cholestérol est un précurseur de toutes les molécules suivantes SAUF :",options:[{text:"Les hormones stéroïdiennes",correct:false},{text:"La vitamine D",correct:false},{text:"Les sels biliaires",correct:false},{text:"Les prostaglandines",correct:true}],explanation:"Le cholestérol est le précurseur des hormones stéroïdiennes (cortisol, aldostérone, testostérone), de la vitamine D3 et des acides biliaires. Les prostaglandines dérivent de l'acide arachidonique (AG polyinsaturé C20:4) via la cyclooxygénase."},
{subject:"chimie",question:"L'ADN est constitué de nucléotides contenant quel sucre ?",options:[{text:"Ribose",correct:false},{text:"Désoxyribose",correct:true},{text:"Glucose",correct:false},{text:"Fructose",correct:false}],explanation:"L'ADN contient du 2'-désoxyribose (absence du -OH en position 2'). L'ARN contient du ribose (avec -OH en 2'). Cette différence rend l'ARN plus hydrolysable et moins stable que l'ADN."},
{subject:"chimie",question:"Les bases puriques de l'ADN sont :",options:[{text:"Cytosine et thymine",correct:false},{text:"Adénine et guanine",correct:true},{text:"Uracile et thymine",correct:false},{text:"Adénine et cytosine",correct:false}],explanation:"Les purines (2 cycles) sont l'adénine (A) et la guanine (G). Les pyrimidines (1 cycle) sont la cytosine (C), la thymine (T) dans l'ADN et l'uracile (U) dans l'ARN. Appariements Watson-Crick : A=T (2 liaisons H), G≡C (3 liaisons H)."},
{subject:"chimie",question:"La constante d'équilibre Kc d'une réaction est liée à ΔG° par :",options:[{text:"ΔG° = RT × Kc",correct:false},{text:"ΔG° = -RT ln(Kc)",correct:true},{text:"ΔG° = RT / Kc",correct:false},{text:"ΔG° = -Kc / RT",correct:false}],explanation:"ΔG° = -RT ln(Kc). Si Kc > 1 → ΔG° < 0 (réaction spontanée dans le sens direct). Si Kc < 1 → ΔG° > 0. À l'équilibre, ΔG = 0 (pas ΔG° qui est une constante)."},
{subject:"chimie",question:"La phosphorylation oxydative produit la majorité de l'ATP cellulaire grâce à :",options:[{text:"La glycolyse",correct:false},{text:"Le gradient de protons et l'ATP synthase",correct:true},{text:"La fermentation",correct:false},{text:"Le cycle de l'urée",correct:false}],explanation:"La chaîne respiratoire crée un gradient de H⁺ (force proton-motrice) à travers la membrane interne mitochondriale. L'ATP synthase (complexe V) utilise ce gradient pour synthétiser l'ATP (chimiosmose de Mitchell). ~30-32 ATP par glucose."},
{subject:"chimie",question:"Un catalyseur modifie :",options:[{text:"L'enthalpie de réaction ΔH",correct:false},{text:"L'énergie d'activation Ea",correct:true},{text:"La constante d'équilibre Kc",correct:false},{text:"Le ΔG de la réaction",correct:false}],explanation:"Un catalyseur abaisse l'énergie d'activation (Ea) sans modifier la thermodynamique (ΔH, ΔG, Kc inchangés). Il accélère l'atteinte de l'équilibre sans le déplacer. Les enzymes sont des biocatalyseurs très spécifiques."},
{subject:"chimie",question:"La réaction de Maillard met en jeu :",options:[{text:"Un sucre réducteur et un acide aminé",correct:true},{text:"Deux acides aminés",correct:false},{text:"Un lipide et un sucre",correct:false},{text:"Un alcool et un acide",correct:false}],explanation:"La réaction de Maillard est une glycation non enzymatique entre un sucre réducteur (glucose, fructose) et une amine libre (lysine, N-terminal). Elle produit des bases de Schiff, puis des produits d'Amadori, et enfin des AGEs (impliqués dans le vieillissement et le diabète)."},
{subject:"chimie",question:"Le glucagon est sécrété par :",options:[{text:"Les cellules β du pancréas",correct:false},{text:"Les cellules α du pancréas",correct:true},{text:"La médullosurrénale",correct:false},{text:"L'hypothalamus",correct:false}],explanation:"Le glucagon est sécrété par les cellules α des îlots de Langerhans (pancréas endocrine). C'est l'hormone hyperglycémiante : il stimule la glycogénolyse et la néoglucogenèse hépatiques. L'insuline est sécrétée par les cellules β."},
{subject:"chimie",question:"Un mélange racémique contient :",options:[{text:"Uniquement l'énantiomère R",correct:false},{text:"Un mélange équimolaire des énantiomères R et S",correct:true},{text:"Un excès de l'énantiomère S",correct:false},{text:"Des diastéréoisomères",correct:false}],explanation:"Un mélange racémique (racémate) contient 50% de R et 50% de S → pouvoir rotatoire nul (les rotations se compensent). L'excès énantiomérique (ee) est nul. Il faut un résolution chirale pour les séparer."},
{subject:"chimie",question:"La vitamine B12 (cobalamine) contient quel métal :",options:[{text:"Fer",correct:false},{text:"Zinc",correct:false},{text:"Cobalt",correct:true},{text:"Cuivre",correct:false}],explanation:"La vitamine B12 contient un atome de cobalt au centre d'un noyau corrine (similaire à la porphyrine). Elle est cofacteur de la méthionine synthase et de la méthylmalonyl-CoA mutase. Sa carence cause l'anémie de Biermer."},
{subject:"chimie",question:"Le point isoélectrique d'une protéine est le pH auquel :",options:[{text:"La protéine est totalement dénaturée",correct:false},{text:"La charge nette de la protéine est nulle",correct:true},{text:"La protéine a sa vitesse de migration maximale",correct:false},{text:"La protéine est entièrement sous forme cationique",correct:false}],explanation:"Au pI, la charge nette est nulle (autant de charges + que de charges -). La protéine ne migre pas en électrophorèse. La solubilité est minimale au pI (précipitation isoélectrique). Le pI dépend de la composition en AA."},
{subject:"chimie",question:"L'ordre de priorité des règles CIP est basé sur :",options:[{text:"La masse atomique des substituants",correct:false},{text:"Le numéro atomique des atomes directement liés",correct:true},{text:"L'électronégativité des substituants",correct:false},{text:"La taille du substituant",correct:false}],explanation:"Les règles CIP classent les substituants par numéro atomique décroissant de l'atome directement lié au centre stéréogène. En cas d'égalité, on compare les atomes suivants (exploration couche par couche). Les liaisons multiples sont 'dédoublées'."},
{subject:"chimie",question:"La condensation d'un acide carboxylique et d'un alcool donne :",options:[{text:"Un éther",correct:false},{text:"Un ester",correct:true},{text:"Un amide",correct:false},{text:"Un anhydride",correct:false}],explanation:"Acide + alcool → ester + H₂O (estérification de Fischer). Réaction réversible, catalysée par H⁺. L'hydrolyse de l'ester (inverse) régénère l'acide et l'alcool. En milieu basique : saponification (irréversible)."},
{subject:"chimie",question:"L'acide gras essentiel linoléique (C18:2 ω-6) est dit essentiel car :",options:[{text:"Il est le plus abondant dans le corps",correct:false},{text:"L'organisme humain ne peut pas le synthétiser",correct:true},{text:"Il est saturé",correct:false},{text:"Il a un nombre impair de carbones",correct:false}],explanation:"Les AG essentiels (linoléique ω-6 et α-linolénique ω-3) ne peuvent pas être synthétisés par l'homme (absence des désaturases Δ12 et Δ15). Ils doivent être apportés par l'alimentation. Ils sont précurseurs des eicosanoïdes."},
{subject:"chimie",question:"La structure secondaire en hélice α est stabilisée par :",options:[{text:"Des ponts disulfures",correct:false},{text:"Des liaisons hydrogène intra-chaîne (C=O···H-N)",correct:true},{text:"Des interactions hydrophobes",correct:false},{text:"Des liaisons ioniques",correct:false}],explanation:"L'hélice α est stabilisée par des liaisons H entre C=O du résidu i et N-H du résidu i+4 (parallèles à l'axe de l'hélice). 3,6 résidus par tour. Les chaînes latérales pointent vers l'extérieur. Les prolines la déstabilisent."},
{subject:"chimie",question:"Le Western blot permet de détecter :",options:[{text:"L'ADN",correct:false},{text:"L'ARN",correct:false},{text:"Les protéines",correct:true},{text:"Les lipides",correct:false}],explanation:"Western blot = protéines (séparation SDS-PAGE + transfert sur membrane + détection par anticorps). Southern blot = ADN. Northern blot = ARN. Moyen mnémotechnique : SNoW (Southern-Northern-Western = DNA-RNA-Protein)."},
{subject:"chimie",question:"Lors de la transcription, l'ARN polymérase synthétise :",options:[{text:"Un brin d'ADN complémentaire",correct:false},{text:"Un ARN messager à partir du brin matrice d'ADN",correct:true},{text:"Des protéines à partir de l'ARNm",correct:false},{text:"De l'ADN à partir d'ARN",correct:false}],explanation:"La transcription : ADN → ARNm par l'ARN polymérase (lit le brin matrice 3'→5', synthétise l'ARN 5'→3'). L'ARN produit est complémentaire du brin matrice et identique (sauf U/T) au brin codant."},
{subject:"chimie",question:"La PCR (Polymerase Chain Reaction) permet de :",options:[{text:"Séquencer les protéines",correct:false},{text:"Amplifier un fragment d'ADN spécifique",correct:true},{text:"Synthétiser des protéines in vitro",correct:false},{text:"Dénaturer les enzymes",correct:false}],explanation:"La PCR amplifie exponentiellement un fragment d'ADN cible grâce à des cycles de : dénaturation (94°C), hybridation des amorces (50-65°C), élongation par la Taq polymérase (72°C). n cycles → 2ⁿ copies théoriques."},
{subject:"chimie",question:"Un acide faible se caractérise par :",options:[{text:"Un pKa < 0",correct:false},{text:"Une dissociation partielle dans l'eau",correct:true},{text:"Une dissociation totale dans l'eau",correct:false},{text:"Un pH toujours supérieur à 7",correct:false}],explanation:"Un acide faible se dissocie partiellement (Ka < 1, pKa > 0). Exemples : acide acétique (pKa 4,75), H₂CO₃ (pKa 6,1). Un acide fort (HCl, H₂SO₄, HNO₃) se dissocie totalement (Ka → ∞)."},
{subject:"chimie",question:"L'équation d'Henderson-Hasselbalch est :",options:[{text:"pH = pKa + log([AH]/[A⁻])",correct:false},{text:"pH = pKa + log([A⁻]/[AH])",correct:true},{text:"pH = pKa - log([A⁻]/[AH])",correct:false},{text:"pH = -log(Ka)",correct:false}],explanation:"pH = pKa + log([A⁻]/[AH]). Quand [A⁻] = [AH] → pH = pKa (pouvoir tampon maximal). Cette équation est fondamentale pour comprendre les tampons biologiques et le pH sanguin."},
{subject:"chimie",question:"Le glycogène est stocké principalement dans :",options:[{text:"Le cerveau et les os",correct:false},{text:"Le foie et les muscles",correct:true},{text:"Le tissu adipeux",correct:false},{text:"Les reins",correct:false}],explanation:"Le glycogène hépatique (~100g, maintient la glycémie) et musculaire (~400g, énergie locale). C'est un polymère ramifié de glucose (liaisons α1→4, branchements α1→6 toutes les 8-12 unités)."},
{subject:"chimie",question:"La décarboxylation oxydative du pyruvate produit :",options:[{text:"Lactate + NAD⁺",correct:false},{text:"Acétyl-CoA + CO₂ + NADH",correct:true},{text:"Oxaloacétate + ATP",correct:false},{text:"Citrate + FADH₂",correct:false}],explanation:"Pyruvate + CoA + NAD⁺ → Acétyl-CoA + CO₂ + NADH. Catalysée par le complexe pyruvate déshydrogénase (PDH) dans la matrice mitochondriale. Réaction irréversible, point de non-retour du catabolisme glucidique."},
{subject:"chimie",question:"Un acide aminé glucoformateur peut être converti en :",options:[{text:"Acides gras uniquement",correct:false},{text:"Glucose par la néoglucogenèse",correct:true},{text:"Cholestérol uniquement",correct:false},{text:"Aucun autre métabolite",correct:false}],explanation:"Les AA glucoformateurs sont dégradés en intermédiaires de la néoglucogenèse (pyruvate, oxaloacétate, etc.). La plupart des AA sont glucoformateurs. La leucine et la lysine sont strictement cétogènes (donnent de l'acétyl-CoA uniquement)."},
{subject:"chimie",question:"L'allostérie d'une enzyme signifie :",options:[{text:"L'enzyme fonctionne sans cofacteur",correct:false},{text:"La fixation d'un effecteur sur un site différent du site actif modifie l'activité",correct:true},{text:"L'enzyme est dénaturée",correct:false},{text:"L'enzyme a une cinétique michaelienne classique",correct:false}],explanation:"Les enzymes allostériques possèdent un site régulateur (allostérique) distinct du site actif. La fixation d'un effecteur positif (activateur) ou négatif (inhibiteur) modifie la conformation et l'activité. Cinétique sigmoïde (non michaelienne)."},
{subject:"chimie",question:"Dans l'isomère Z d'un alcène :",options:[{text:"Les groupes prioritaires sont du même côté de la double liaison",correct:true},{text:"Les groupes prioritaires sont de part et d'autre",correct:false},{text:"La molécule est plane et symétrique",correct:false},{text:"Il n'y a pas de double liaison",correct:false}],explanation:"Z (zusammen = ensemble) : les groupes de plus haute priorité (CIP) sont du même côté. E (entgegen = opposé) : de part et d'autre. Z correspond souvent (mais pas toujours) à la configuration cis."},
{subject:"chimie",question:"Le cycle de l'urée se déroule principalement dans :",options:[{text:"Le rein",correct:false},{text:"Le foie",correct:true},{text:"Le muscle",correct:false},{text:"Le cerveau",correct:false}],explanation:"Le cycle de l'urée (uréogenèse) est hépatique : il convertit l'ammoniac toxique (NH₃) en urée (non toxique, excrétée par le rein). Il consomme 3 ATP par tour. Les 2 azotes de l'urée proviennent du NH₄⁺ et de l'aspartate."},
{subject:"chimie",question:"La vitamine C (acide ascorbique) est un :",options:[{text:"Cofacteur des kinases",correct:false},{text:"Antioxydant et cofacteur de la prolyl-hydroxylase",correct:true},{text:"Précurseur du NAD⁺",correct:false},{text:"Composant des membranes cellulaires",correct:false}],explanation:"La vitamine C est un puissant antioxydant (piégeur de radicaux libres) et cofacteur de la prolyl-hydroxylase (hydroxylation du collagène). Sa carence provoque le scorbut (fragilité vasculaire, déchaussement dentaire)."},
{subject:"chimie",question:"Le réactif de Grignard (RMgX) est utilisé pour :",options:[{text:"L'oxydation des alcools",correct:false},{text:"La formation de liaisons C-C (addition nucléophile)",correct:true},{text:"La réduction des cétones en alcanes",correct:false},{text:"La polymérisation",correct:false}],explanation:"Le réactif de Grignard (organomagnésien) est un puissant nucléophile (R⁻). Il s'additionne sur les carbonyles : RMgX + aldéhyde → alcool secondaire, RMgX + cétone → alcool tertiaire, RMgX + CO₂ → acide carboxylique."},
{subject:"chimie",question:"Les corps cétoniques sont produits dans :",options:[{text:"Le muscle",correct:false},{text:"Le foie à partir d'acétyl-CoA",correct:true},{text:"Le cerveau",correct:false},{text:"Les globules rouges",correct:false}],explanation:"La cétogenèse hépatique produit les corps cétoniques (acétoacétate, β-hydroxybutyrate, acétone) à partir d'acétyl-CoA en excès (jeûne, diabète). Ils sont utilisés comme substrat énergétique par le cerveau, le cœur et le muscle."},
{subject:"chimie",question:"La chromatographie d'exclusion stérique sépare les protéines selon :",options:[{text:"Leur charge",correct:false},{text:"Leur taille (masse moléculaire)",correct:true},{text:"Leur hydrophobicité",correct:false},{text:"Leur affinité pour un ligand",correct:false}],explanation:"La chromatographie d'exclusion (gel-filtration) sépare par taille : les grosses molécules sont exclues des pores du gel et éluent en premier, les petites pénètrent les pores et sont retardées. Pas d'interaction chimique avec le gel."},
{subject:"chimie",question:"Le SDS-PAGE sépare les protéines selon :",options:[{text:"Leur charge native",correct:false},{text:"Leur masse moléculaire",correct:true},{text:"Leur point isoélectrique",correct:false},{text:"Leur activité enzymatique",correct:false}],explanation:"Le SDS (dodécylsulfate de sodium) dénature les protéines et leur confère une charge négative uniforme proportionnelle à leur masse. La séparation se fait uniquement par taille dans le gel de polyacrylamide."},
{subject:"chimie",question:"Un composé méso est :",options:[{text:"Un énantiomère pur",correct:false},{text:"Un composé achiral malgré la présence de centres stéréogènes",correct:true},{text:"Un mélange racémique",correct:false},{text:"Un diastéréoisomère toujours actif optiquement",correct:false}],explanation:"Un composé méso possède des centres stéréogènes mais est achiral en raison d'un plan de symétrie interne. Les rotations des centres se compensent → pouvoir rotatoire nul. Exemple : acide tartrique méso."},
{subject:"chimie",question:"La phosphofructokinase-1 (PFK-1) est l'enzyme clé de régulation de :",options:[{text:"La néoglucogenèse",correct:false},{text:"La glycolyse",correct:true},{text:"La β-oxydation",correct:false},{text:"Le cycle de Krebs",correct:false}],explanation:"La PFK-1 catalyse la phosphorylation du fructose-6-P en fructose-1,6-bisphosphate (étape irréversible et limitante de la glycolyse). Elle est activée par l'AMP et le fructose-2,6-bisP, inhibée par l'ATP et le citrate."},
{subject:"chimie",question:"Le potentiel standard d'oxydoréduction E° du couple NAD⁺/NADH vaut environ :",options:[{text:"+0,82 V",correct:false},{text:"-0,32 V",correct:true},{text:"0 V",correct:false},{text:"+0,34 V",correct:false}],explanation:"E°'(NAD⁺/NADH) = -0,32 V. E°'(O₂/H₂O) = +0,82 V. Les électrons vont du NADH (bas E°) vers O₂ (haut E°), libérant de l'énergie (ΔG < 0) utilisée pour pomper les protons dans la chaîne respiratoire."},
{subject:"chimie",question:"Un nucléoside est constitué de :",options:[{text:"Base azotée + sucre + phosphate",correct:false},{text:"Base azotée + sucre",correct:true},{text:"Sucre + phosphate",correct:false},{text:"Base azotée uniquement",correct:false}],explanation:"Nucléoside = base + sucre (ribose ou désoxyribose). Nucléotide = nucléoside + phosphate(s). Exemples : adénosine (nucléoside) → AMP → ADP → ATP (nucléotides mono/di/triphosphate)."},
{subject:"chimie",question:"La synthèse des acides gras (lipogenèse) se déroule dans :",options:[{text:"La mitochondrie",correct:false},{text:"Le cytoplasme",correct:true},{text:"Le noyau",correct:false},{text:"Le réticulum endoplasmique rugueux",correct:false}],explanation:"La lipogenèse (synthèse des AG) est cytoplasmique, catalysée par l'acide gras synthase (FAS). Elle utilise l'acétyl-CoA (exporté de la mitochondrie via le citrate), le NADPH et le malonyl-CoA. Inverse de la β-oxydation (mitochondriale)."},
{subject:"chimie",question:"Le principe de Le Chatelier prédit qu'une augmentation de pression favorise :",options:[{text:"Le sens qui produit plus de moles gazeuses",correct:false},{text:"Le sens qui produit moins de moles gazeuses",correct:true},{text:"Toujours le sens direct",correct:false},{text:"N'a aucun effet sur l'équilibre",correct:false}],explanation:"Selon Le Chatelier, une augmentation de pression déplace l'équilibre vers le sens qui diminue le nombre de moles gazeuses. Si Δn(gaz) = 0, la pression n'a pas d'effet. La température et la concentration suivent le même principe."},
{subject:"chimie",question:"Les vitamines liposolubles sont :",options:[{text:"B et C",correct:false},{text:"A, D, E, K",correct:true},{text:"B1, B6, B12",correct:false},{text:"C et PP",correct:false}],explanation:"ADEK : vitamines liposolubles (stockées dans le tissu adipeux et le foie → risque d'hypervitaminose). Les vitamines hydrosolubles (B, C) ne sont pas stockées (excès éliminé dans les urines) sauf B12 (réserves hépatiques pour 3-5 ans)."},
{subject:"chimie",question:"L'énergie de liaison diminue quand :",options:[{text:"L'ordre de liaison augmente",correct:false},{text:"La longueur de liaison augmente",correct:true},{text:"La charge nucléaire effective augmente",correct:false},{text:"Les atomes sont de petite taille",correct:false}],explanation:"Plus la liaison est longue, plus elle est faible (énergie de dissociation faible). Liaison simple < double < triple en énergie (et en longueur inversement). Exemple : C-C (347 kJ/mol) < C=C (614) < C≡C (839)."},
{subject:"chimie",question:"Un zwitterion est :",options:[{text:"Une molécule portant simultanément une charge + et une charge -",correct:true},{text:"Un ion monovalent",correct:false},{text:"Un atome neutre",correct:false},{text:"Une molécule totalement déprotonée",correct:false}],explanation:"Un zwitterion (ion dipolaire) porte à la fois une charge positive et une charge négative, avec une charge nette nulle. Les acides aminés existent sous forme zwitterionique à pH physiologique : -NH₃⁺ et -COO⁻."},
{subject:"chimie",question:"Quel type de chromatographie utilise un anticorps fixé sur la colonne ?",options:[{text:"Échangeuse d'ions",correct:false},{text:"D'affinité",correct:true},{text:"D'exclusion stérique",correct:false},{text:"En phase inverse",correct:false}],explanation:"La chromatographie d'affinité exploite l'interaction spécifique entre une molécule cible et un ligand immobilisé (anticorps, substrat, lectine). La protéine cible est retenue spécifiquement puis éluée par compétition ou changement de conditions."},
{subject:"chimie",question:"La réaction de transaminase :",options:[{text:"Élimine le groupe amine sous forme de NH₃",correct:false},{text:"Transfère le groupe amine d'un AA à un α-cétoacide",correct:true},{text:"Hydrolyse les liaisons peptidiques",correct:false},{text:"Réduit le NAD⁺ en NADH",correct:false}],explanation:"Les transaminases (aminotransférases) transfèrent le -NH₂ d'un AA donneur vers un α-cétoacide accepteur (souvent α-cétoglutarate → glutamate). Cofacteur : pyridoxal-phosphate (PLP, vitamine B6). ASAT et ALAT sont des marqueurs hépatiques."},
{subject:"chimie",question:"Le pKa de l'acide acétique est 4,75. À pH 4,75, le rapport [CH₃COO⁻]/[CH₃COOH] vaut :",options:[{text:"0",correct:false},{text:"1",correct:true},{text:"10",correct:false},{text:"100",correct:false}],explanation:"Henderson-Hasselbalch : pH = pKa + log([A⁻]/[AH]). Si pH = pKa → log([A⁻]/[AH]) = 0 → [A⁻]/[AH] = 1. Les formes acide et basique sont en concentrations égales. C'est le point de pouvoir tampon maximal."},
{subject:"chimie",question:"L'anomérie (α et β) du glucose concerne :",options:[{text:"La configuration du C5",correct:false},{text:"La configuration du carbone anomérique (C1) en forme cyclique",correct:true},{text:"L'isomérie E/Z",correct:false},{text:"La taille du cycle",correct:false}],explanation:"Lors de la cyclisation du glucose, le C1 (carbonyle) devient un nouveau centre asymétrique (carbone anomérique). α : OH du C1 axial (même côté que le cycle). β : OH du C1 équatorial (opposé). La mutarotation est l'interconversion α ⇌ β en solution."},
{subject:"chimie",question:"Le FADH₂ entre dans la chaîne respiratoire au niveau du :",options:[{text:"Complexe I",correct:false},{text:"Complexe II",correct:true},{text:"Complexe IV",correct:false},{text:"ATP synthase",correct:false}],explanation:"Le FADH₂ cède ses électrons au complexe II (succinate déshydrogénase, seul complexe qui ne pompe pas de protons). Le NADH entre au complexe I. Le FADH₂ produit donc moins d'ATP (~1,5) que le NADH (~2,5)."},
{subject:"chimie",question:"L'acide pyruvique possède combien de carbones ?",options:[{text:"2",correct:false},{text:"3",correct:true},{text:"4",correct:false},{text:"6",correct:false}],explanation:"Le pyruvate (CH₃-CO-COO⁻) a 3 carbones. C'est le produit final de la glycolyse (glucose 6C → 2 pyruvates 3C). Il est au carrefour métabolique : → acétyl-CoA (aérobie), → lactate (anaérobie), → oxaloacétate (néoglucogenèse)."},
{subject:"chimie",question:"La liaison hydrogène typique a une énergie d'environ :",options:[{text:"400-500 kJ/mol",correct:false},{text:"10-40 kJ/mol",correct:true},{text:"0,1-1 kJ/mol",correct:false},{text:"100-200 kJ/mol",correct:false}],explanation:"Les liaisons H ont une énergie de ~10-40 kJ/mol (intermédiaire entre van der Waals ~1-5 kJ/mol et covalente ~200-800 kJ/mol). Elles sont essentielles : structure de l'eau, appariement ADN, structure des protéines."},
{subject:"chimie",question:"Le coenzyme A contient quelle vitamine ?",options:[{text:"B1 (thiamine)",correct:false},{text:"B5 (acide pantothénique)",correct:true},{text:"B6 (pyridoxine)",correct:false},{text:"B9 (acide folique)",correct:false}],explanation:"Le CoA contient l'acide pantothénique (vitamine B5), la cystéamine et l'ADP 3'-phosphate. Le groupement thiol (-SH) du CoA forme des thioesters avec les acyl (acétyl-CoA, succinyl-CoA, acyl-CoA des AG)."},
];
